import React from 'react';
import Header from '../components/Header';

const ContactUs = () => {
  return (
    <div className="min-h-screen flex flex-col bg-gray-900 text-white">
      <Header />
      <main className="flex-1 overflow-y-auto">
        <div className="max-w-3xl mx-auto px-4 py-10 sm:py-12">
          <h1 className="text-3xl sm:text-4xl font-bold mb-6">Contact Us</h1>
          <p className="text-gray-300 leading-relaxed text-base sm:text-lg mb-8">
            We welcome questions about FlameFlux, partnerships, and collaboration. Reach out using the
            contact details below (to be updated).
          </p>
          <div className="rounded-lg border border-gray-600 bg-gray-800/50 p-6 text-gray-400">
            <p className="text-sm">General inquiries: add your email or form here.</p>
          </div>
        </div>
      </main>
    </div>
  );
};

export default ContactUs;
